+fn normalize_registry_name(raw: &str) -> String {
+    let mut normalized = raw
+        .trim()
+        .to_ascii_lowercase()
+        .chars()
+        .map(|ch| {
+            if ch.is_ascii_alphanumeric() || ch == '-' || ch == '_' {
+                ch
+            } else {
+                '-'
+            }
+        })
+        .collect::<String>();
+    normalized = normalized.trim_matches('-').to_string();
+    if normalized.is_empty() {
+        "extension-artifact".to_string()
+    } else {
+        normalized
+    }
+}
