+fn parse_min_assurance(raw: Option<u8>) -> Result<Option<u8>> {
+    let Some(value) = raw else {
+        return Ok(None);
+    };
+    if (1..=5).contains(&value) {
+        Ok(Some(value))
+    } else {
+        anyhow::bail!("invalid --min-assurance `{value}`; expected a value between 1 and 5");
+    }
+}
